def logger(func):
    def wrapper(*args):
        print('Call')
        return func(*args)
    return wrapper

@logger
def add(x, y):
    return x + y

result = add(2, 3)
print(result)

def repeat(n):
    def decorator(func):
        def wrapper(*args):
            for _ in range(n):
                func(*args)
        return wrapper
    return decorator

@repeat(3)
def hello():
    print('Hi')

hello()

def timer(func):
    def wrapper():
        print('Start')
        func()
        print('End')
    return wrapper

@timer
def task():
    print('Running')

task()

def check_positive(func):
    def wrapper(x):
        if x < 0:
            return 'Negative'
        return func(x)
    return wrapper

@check_positive
def double(x):
    return x * 2

print(double(-3))
print(double(5))

def memoize(func):
    cache = {}
    def wrapper(n):
        if n not in cache:
            cache[n] = func(n)
        return cache[n]
    return wrapper

@memoize
def square(n):
    return n * n

print(square(4))
print(square(4))

